sql.where:
COALESCE(u.is_deleted, false) = false

    AND (u.user_id ILIKE '%' || #{keyword} || '%'
      OR u.user_nm ILIKE '%' || #{keyword} || '%'
      OR COALESCE(u.user_info ->> 'email_id', '') ILIKE '%' || #{keyword} || '%')


    AND u.user_info ->> 'grade_cd' = #{gradeCd}


    AND u.user_info ->> 'auth_group' = #{authGroup}
